class Solution:
    def licenseKeyFormatting(self, s: str, k: int) -> str:
        t = "".join(ch.upper() for ch in s if ch != "-")
        if not t: return ""
        rem = len(t) % k
        parts = []
        if rem: parts.append(t[:rem])
        for i in range(rem, len(t), k):
            parts.append(t[i:i+k])
        return "-".join(parts)

